// Build a unified scan session context from either trigger
const body = $input.item.json?.body || $input.item.json || {};

const scanSession = {
  scanSessionId: `VSCAN-${Date.now()}-${Math.random().toString(36).substr(2, 8).toUpperCase()}`,
  scanType: body.scanType || 'scheduled',
  priority: body.priority || 'normal',
  requestedBy: body.requestedBy || 'scheduler',
  targetScope: body.targetScope || 'all',
  targetHosts: body.targetHosts || [],
  includeScanners: body.includeScanners || ['nessus', 'qualys', 'custom'],
  minCvssThreshold: parseFloat(body.minCvssThreshold) || 0.0,
  initiatedAt: new Date().toISOString(),
  environment: body.environment || 'production'
};

return { json: { scanSession } };

const scanSession = $('Build Scan Context').first().json.scanSession;
const nessusRaw = $('Fetch Nessus Scan Results').all().map(i => i.json);
const qualysRaw = $('Fetch Qualys Scan Results').all().map(i => i.json);
const customRaw = $('Fetch Custom Scanner Results').all().map(i => i.json);

// ---- Normalize Nessus findings ----
const nessusFindings = (nessusRaw[0]?.vulnerabilities || nessusRaw[0]?.findings || []).map(v => ({
  source: 'nessus',
  cveId: v.cve || v.cveId || v.plugin_id || 'NO-CVE',
  pluginId: v.plugin_id || v.pluginId || null,
  hostIp: v.host_ip || v.ip || 'unknown',
  hostName: v.hostname || v.hostName || v.host_ip || 'unknown',
  port: v.port || null,
  protocol: v.protocol || null,
  cvssScore: parseFloat(v.cvss_base_score || v.cvssScore || v.severity_index || 0),
  cvssVector: v.cvss_vector || null,
  severity: v.severity || (v.cvss_base_score >= 9 ? 'CRITICAL' : v.cvss_base_score >= 7 ? 'HIGH' : v.cvss_base_score >= 4 ? 'MEDIUM' : 'LOW'),
  title: v.plugin_name || v.title || v.description || 'Unknown Vulnerability',
  description: v.description || v.synopsis || '',
  solution: v.solution || '',
  firstSeen: v.first_seen || new Date().toISOString(),
  lastSeen: v.last_seen || new Date().toISOString(),
  assetCriticality: v.asset_criticality || 'medium'
}));

// ---- Normalize Qualys findings ----
const qualysFindings = (qualysRaw[0]?.HOST_LIST?.HOST || []).flatMap(host => {
  const detections = host.DETECTION_LIST?.DETECTION || [];
  return (Array.isArray(detections) ? detections : [detections]).map(d => ({
    source: 'qualys',
    cveId: d.CVE_LIST?.CVE?.[0]?.ID || d.QID || 'NO-CVE',
    pluginId: d.QID || null,
    hostIp: host.IP || 'unknown',
    hostName: host.DNS || host.IP || 'unknown',
    port: d.PORT || null,
    protocol: d.PROTOCOL || null,
    cvssScore: parseFloat(d.CVSS_FINAL || d.CVSS3_FINAL || 0),
    cvssVector: null,
    severity: d.SEVERITY === '5' ? 'CRITICAL' : d.SEVERITY === '4' ? 'HIGH' : d.SEVERITY === '3' ? 'MEDIUM' : 'LOW',
    title: d.RESULTS || 'Qualys Finding',
    description: d.RESULTS || '',
    solution: '',
    firstSeen: d.FIRST_FOUND_DATETIME || new Date().toISOString(),
    lastSeen: d.LAST_FOUND_DATETIME || new Date().toISOString(),
    assetCriticality: 'medium'
  }));
});

// ---- Normalize Custom scanner findings ----
const customFindings = (customRaw[0]?.data || customRaw[0]?.vulnerabilities || customRaw || []).map(v => ({
  source: 'custom',
  cveId: v.cveId || v.cve_id || v.identifier || 'NO-CVE',
  pluginId: v.checkId || v.pluginId || null,
  hostIp: v.hostIp || v.ip_address || 'unknown',
  hostName: v.hostName || v.hostname || 'unknown',
  port: v.port || null,
  protocol: v.protocol || null,
  cvssScore: parseFloat(v.cvssScore || v.cvss || 0),
  cvssVector: v.cvssVector || null,
  severity: v.severity?.toUpperCase() || 'LOW',
  title: v.title || v.name || 'Custom Finding',
  description: v.description || '',
  solution: v.remediation || v.solution || '',
  firstSeen: v.firstDetected || new Date().toISOString(),
  lastSeen: v.lastDetected || new Date().toISOString(),
  assetCriticality: v.assetCriticality || 'medium'
}));

// ---- Merge all ----
const allFindings = [...nessusFindings, ...qualysFindings, ...customFindings];

// ---- Deduplicate by cveId + hostIp ----
const seen = new Set();
const deduped = allFindings.filter(f => {
  const key = `${f.cveId}::${f.hostIp}::${f.port || 'any'}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

// ---- Apply CVSS severity normalization ----
const normalized = deduped.map(f => {
  const score = f.cvssScore;
  const severity = score >= 9.0 ? 'CRITICAL' : score >= 7.0 ? 'HIGH' : score >= 4.0 ? 'MEDIUM' : 'LOW';
  return {
    ...f,
    severity,
    vulnId: `VID-${Date.now()}-${Math.random().toString(36).substr(2, 6).toUpperCase()}`,
    scanSessionId: scanSession.scanSessionId,
    detectedAt: new Date().toISOString(),
    status: 'OPEN'
  };
});

// Filter by configured threshold
const filtered = normalized.filter(f => f.cvssScore >= scanSession.minCvssThreshold);

const stats = {
  total: filtered.length,
  critical: filtered.filter(f => f.severity === 'CRITICAL').length,
  high: filtered.filter(f => f.severity === 'HIGH').length,
  medium: filtered.filter(f => f.severity === 'MEDIUM').length,
  low: filtered.filter(f => f.severity === 'LOW').length,
  fromNessus: nessusFindings.length,
  fromQualys: qualysFindings.length,
  fromCustom: customFindings.length,
  duplicatesRemoved: allFindings.length - deduped.length
};

return filtered.map(vuln => ({ json: { scanSession, vuln, stats } }));

const aiResponse = $input.item.json;
let aiText = aiResponse.response || aiResponse.output || aiResponse.text || '';
if (aiResponse.content && Array.isArray(aiResponse.content)) {
  aiText = aiResponse.content[0]?.text || aiResponse.content[0]?.message?.content || '';
}
const clean = aiText.replace(/```json\s*/g,'').replace(/```\s*/g,'').trim();

let riskAssessment;
try { riskAssessment = JSON.parse(clean); }
catch(e) { throw new Error(`GPT-4 parse failed: ${e.message}. Raw: ${clean.substring(0,200)}`); }

// Reconstruct full vuln record from upstream
const upstream = $('Normalize and Deduplicate Findings').item.json;

// SLA due date calculation
const slaDays = riskAssessment.slaDays || (riskAssessment.priorityTier === 'P1-CRITICAL' ? 1 : riskAssessment.priorityTier === 'P2-HIGH' ? 7 : riskAssessment.priorityTier === 'P3-MEDIUM' ? 30 : 90);
const dueDate = new Date(Date.now() + slaDays * 24 * 60 * 60 * 1000).toISOString();

return {
  json: {
    scanSession: upstream.scanSession,
    vuln: upstream.vuln,
    stats: upstream.stats,
    riskAssessment,
    slaDays,
    dueDate,
    isCriticalOrHigh: ['CRITICAL', 'HIGH'].includes(upstream.vuln.severity),
    isCritical: upstream.vuln.severity === 'CRITICAL',
    enrichedAt: new Date().toISOString()
  }
};

