const allVulns = $input.all().map(i => i.json);
const now = new Date();
const oneWeekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

// Filter vulns detected this week
const weekVulns = allVulns.filter(v => v.detectedAt && new Date(v.detectedAt) >= oneWeekAgo);

// Stats
const total = weekVulns.length;
const critical = weekVulns.filter(v => v.severity === 'CRITICAL');
const high = weekVulns.filter(v => v.severity === 'HIGH');
const medium = weekVulns.filter(v => v.severity === 'MEDIUM');
const low = weekVulns.filter(v => v.severity === 'LOW');
const patched = weekVulns.filter(v => v.status === 'PATCHED');
const open = weekVulns.filter(v => v.status === 'OPEN');
const overdue = open.filter(v => v.dueDate && new Date(v.dueDate) < now);
const withExploit = weekVulns.filter(v => String(v.exploitAvailable).toLowerCase() === 'true');
const kevConfirmed = weekVulns.filter(v => v.cisakevStatus === 'confirmed');

// SLA compliance rate
const slaCompliant = patched.filter(v => {
  const closedDate = v.closedAt ? new Date(v.closedAt) : null;
  const dueDate = v.dueDate ? new Date(v.dueDate) : null;
  return closedDate && dueDate && closedDate <= dueDate;
}).length;
const slaComplianceRate = patched.length > 0 ? Math.round((slaCompliant / patched.length) * 100) : 100;

// MTTD / MTTR (from detectedAt vs closedAt)
const closedThisWeek = patched.filter(v => v.closedAt);
const avgMttrHours = closedThisWeek.length > 0
  ? Math.round(closedThisWeek.reduce((sum, v) => {
      const detected = new Date(v.detectedAt);
      const closed = new Date(v.closedAt);
      return sum + (closed - detected) / (1000 * 60 * 60);
    }, 0) / closedThisWeek.length)
  : 0;

// Top hosts
const hostCounts = {};
weekVulns.forEach(v => { hostCounts[v.hostName] = (hostCounts[v.hostName] || 0) + 1; });
const topHosts = Object.entries(hostCounts).sort((a, b) => b[1] - a[1]).slice(0, 5);

const weekLabel = `${oneWeekAgo.toDateString()} – ${now.toDateString()}`;

return [{
  json: {
    reportPeriod: weekLabel,
    generatedAt: now.toISOString(),
    stats: {
      total, critical: critical.length, high: high.length, medium: medium.length, low: low.length,
      patched: patched.length, open: open.length, overdue: overdue.length,
      withExploit: withExploit.length, kevConfirmed: kevConfirmed.length,
      slaComplianceRate, avgMttrHours
    },
    topVulnerableHosts: topHosts,
    topCritical: critical.slice(0, 5).map(v => ({ cveId: v.cveId, host: v.hostName, score: v.cvssScore, action: v.recommendedAction })),
    overdueVulns: overdue.slice(0, 10).map(v => ({ cveId: v.cveId, host: v.hostName, severity: v.severity, dueDate: v.dueDate }))
  }
}];
